import osimport reimport sysimport globimport tomlimport loggingimport shutilimport time as tmimport numba as nbimport numpy as npfrom tqdm import tqdmfrom datetime import datetime as dtfrom scipy.stats import landau, expon, norm, cauchyfrom cosmic_rays import preprocessing as ppimport multiprocessing as mpfrom cosmic_rays.model import Model as mdfrom cosmic_rays.utils import write_resultsfrom cosmic_rays.plots import Plots as my_pltfrom cosmic_rays.utils import get_tes_asic_from_indexfrom cosmic_rays.mixedDistribution import MixedDistributionfrom qubicpack.qubicfp import qubicfpfrom qubicpack.utilities import NPIXELSimport matplotlib.pyplot as pltclass Crd:    """    Manages datasets, configurations, and analysis for TES data.    The Crd class handles tasks such as reading configurations, organizing datasets,    and preprocessing the TOD data. Its goal is to identify cosmic rays in the preprocessed TODs.    :ivar source: Path(s) to the data source(s).    :ivar dest: Target path for storing results.    :ivar exclude: List of folders or datasets to exclude from the analysis.    :ivar points_vertical_trend: Number of points used to calculate vertical trend.    :ivar points_exp_decrease: Number of points used to observe exponential decrease.    :ivar mask: Mask applied for taking into account IV curve sign or path to the mask files folder.    :ivar analysis_type: Specifies the analysis mode ('all', 'range', 'sequence'). 'All' analyzes all TESs,        'range' analyzes a specific range of TESs, and 'sequence' analyzes a specific sequence of TESs.    :ivar analysis_type_args: Additional arguments for a specific analysis mode. For 'range' mode,        it is an interval of TES indices to be analyzed; for 'sequence' mode, it is a list of TES indices to be analysed.    :ivar noise_points: Number of points used to first calculate noise before and after a cosmic ray candidate.    :ivar remove_files: Indicates if original files (raw TOD, time, azimuth, and elevation) should be removed after analysis        (maintaining only the preprocessed TOD files in a npz format).    :ivar save_results: Specifies if analysis results are automatically saved.    """    # Class attribute representing the TES analysis mode (refer to the `check_mode` method)    MODE = ('all', 'range', 'sequence')    def __init__(self,                 source: str | list[str],                 dest: str | list[str],                 exclude: list[str] | None = None,                 points_vertical_trend: int = 3,                 points_exp_decrease: int = 6,                 mask: str | list[list[int]] = '',                 analysis_type: str = 'all',                 analysis_type_args: list[int] = None,                 noise_points: int = 20,                 remove_files: bool = False,                 save_results: bool = True):        # attributes        self.source = source        self.dest = dest        self.exclude = exclude        self.points_exp_decrease = points_exp_decrease        self.points_vertical_trend = points_vertical_trend        self.mask = mask        self.analysis_type = analysis_type        self.analysis_type_args = analysis_type_args        self.noise_points = noise_points        self.remove_files = remove_files        self.save_results = save_results        self.logger: logging.Logger | None = None        self.logfname: str = ''        self.fs = 0.        self.std_coeff = 5        self.observation_dir: str = ''        self.input_dir: str = ''        self.output_dir: str = ''        self.datasets: dict[str, list[str]] = dict()        self.plots_dir = ''        self.taus_fname = ''        self.time_fname = ''        self.signals_fname = ''        self.elev_fname = ''        self.az_fname = ''        self.thermometers = (4, 36, 68, 100)        self.taus = dict()    @classmethod    def read_config(cls, path: str):        """        Reads configuration details from a specified TOML file path, extracts relevant        settings, and returns a Crd object configured accordingly.        :param path: The path to the TOML configuration file.        :type path: str        :return: An instance of the class initialized with the extracted settings.        :rtype: Crd        """        # Load the TOML configuration from the specified path        config = toml.load(path)        # Retrieve mandatory source path from the config        source = config["path"]["source"]        # Retrieve optional destination path or default to the current working directory        dest = config["optional"].get("destination", os.getcwd())        # Retrieve the dataset exclusion list or default to an empty list        exclude = config["optional"].get("exclude", [])        # Retrieve optional mask information or None if not specified        mask = config["optional"].get("mask", None)        # Retrieve optional number of points for vertical trend; defaults to 3        vertical_points = config["optional"].get("vertical_points", 3)        # Retrieve optional number of points for exponential decay; defaults to 6        exponential_points = config["optional"].get("exponential_points", 6)        # Retrieve optional analysis type; defaults to 'all' (all TES to be analyzed)        analysis_type = config["optional"].get("analysis_type", "all")        # Retrieve optional noise points; number of points used to first calculate        # noise before and after a cosmic ray candidate        noise_points = config["optional"].get("noise_points", 20)        # Retrieve TES analysis argument, which may be a list; defaults to [-1] (all TES to be analyzed)        tes = config['optional'].get('tes', [-1])        # Retrieve optional boolean for file removal; defaults to True        remove_files = config["optional"].get("remove_files", True)        # Retrieve optional boolean for saving results; defaults to True        save_results = config["optional"].get("save_results", True)        # Retrieve optional dpi resolution        my_plt.dpi = config["optional"].get("dpi", 300)        # Instantiate and return a Crd object with the extracted configuration        return cls(source=source,                   dest=dest,                   points_vertical_trend=vertical_points,                   points_exp_decrease=exponential_points,                   mask=mask,                   analysis_type=analysis_type,                   analysis_type_args=tes,                   noise_points=noise_points,                   remove_files=remove_files,                   save_results=save_results)    def get_datasets(self):        """        Retrieves and organizes dataset paths based on specified scanning strategies        or provided source paths. Supports handling multiple scanning strategies        indicated within parentheses in the provided paths. Please refer to the config        files to properly construct the source paths.        Dataset paths are filtered to exclude directories specified in `self.exclude`        and further validated to ensure they contain necessary subdirectories such as        'Hks', 'Raws', and 'Sums'. The resulting paths are categorized and sorted        in descending order for each scanning strategy.        :param self: Instance of the class containing `self.source`, `self.dest`,            `self.datasets`, and `self.exclude` attributes.        :return: A dictionary mapping scanning strategies to lists of corresponding            sorted dataset paths.        :rtype: dict        """        # If 'source' is a single path, convert it to a list; otherwise, use the original list        source = self.source if isinstance(self.source, list) else [self.source]        # Iterate over each path in 'source'        for path in source:            # Prepare a list to hold the dataset paths for each scanning strategy            datasets = []            # 'tokens' is a list of scanning strategies or the single destination path            tokens = [self.dest]            # If the path contains parentheses, it indicates multiple scanning strategies            if '(' in path:                # Split the path into the main (root) part and the parenthetical part (other)                root, other = path.split('(')                # Extract tokens (scanning strategies) within the parentheses.                # Each token is trimmed of whitespace, and the trailing ')*' is removed                tokens = [token.strip() for token in other.rstrip(')*').split(',')]                # For each strategy, append the root path plus token (with a wildcard) to 'datasets'                datasets.extend([root + token + '*' for token in tokens])            else:                # If there's no parenthesis, treat the path as a single dataset                datasets.append(path)            # Match each scanning strategy with the corresponding dataset path            for dt_category, dt_path in zip(tokens, datasets):                # If the strategy token differs from 'self.dest', join them into one path                dt_category = dt_category if dt_category == self.dest else os.path.join(self.dest, dt_category)                # Initialize or retrieve the existing list of dataset paths for this strategy                self.datasets[dt_category] = self.datasets.get(dt_category, [])                # Look for valid dataset folders by searching through all matching directories                for folder in glob.glob(dt_path):                    # Recursively walk through each folder, checking subdirectories and files                    for root, dirs, files in os.walk(folder):                        # A valid dataset folder must contain these specific subdirectories                        if all(d in dirs for d in ['Hks', 'Raws', 'Sums']):                            self.datasets[dt_category] = self.datasets[dt_category] + [root]                # Sort the dataset paths for this strategy in descending (reverse) order                self.datasets[dt_category] = sorted(self.datasets[dt_category], reverse=True)        # Return the dictionary of scanning strategies and their corresponding dataset paths        return self.datasets    @staticmethod    def cmp_mask_by_date(target: str, selected: str) -> float:        """        Compares the iv mask and dataset filenames based on their date/timestamp portion and returns        the time difference in seconds.        :param target: Filename representing the dataset. Must contain a datetime string            at the start, formatted as 'YYYY-MM-DD_HH.MM.SS...'.        :type: str        :param selected: Filename representing the iv mask. Must contain a datetime string            at the start, formatted as 'YYYY-MM-DD_HH.MM.SS...'.       :return: The absolute difference in seconds between the date-time values extracted            from the two input strings.       :rtype: float        """        # Extract and parse the datetime portion (first two tokens separated by '_') in the 'target' string        t_dtime = dt.strptime('_'.join(target.split('_')[:2]), '%Y-%m-%d_%H.%M.%S')        # Extract and parse the datetime portion (first two tokens separated by '_') in the 'selected' string        s_dtime = dt.strptime('_'.join(selected.split('_')[:2]), '%Y-%m-%d_%H.%M.%S')        # Return the difference in total seconds between the two parsed datetimes        return abs(t_dtime - s_dtime).total_seconds()    @staticmethod    def check_mask(mask_fname: str) -> list[list[int]] | None:        """        Validates a mask file that contains TES indices for two different signs (positive or negative).        The file can have at most two rows:          • The first row for positive TES indices, or -1 if none.          • The second row for negative TES indices, or -1 if none.        Examples of valid mask files:        1) No positive TES, only negative TES:             -1             2 4 5 7 13 14 15 18 19 25 26 28 29 30 31 32 33 50        -----------------------------------------------------        2) Only positive TES, no negative TES:             2 4 5 7 13 14 15 18 19 25 26 28 29 30 31 32 33 50             -1        -----------------------------------------------------        3) Both positive and negative TES:             2 4 5 7 13 14 15 18 19 25 26 28 29 30 31 32 33 50             52 60 71 65 74 79        -----------------------------------------------------        :param mask_fname: Path to the file containing the TES mask. Each row must consist of            integers (digit strings), either multiple non-negative integers or            a single -1.        :type: str        :return: A list of rows, where each row contains the integer-converted TES indices.            Returns None if the file is invalid or does not adhere to the required            structure.        :rtype: list[list[int]] | None        """        # Check if the mask file exists        if not os.path.isfile(mask_fname):            return None        # Read the entire file and convert it into a list of lines        with open(mask_fname, 'r') as fin:            mask = fin.readlines()        # Verify that the file contains 1 or 2 lines only, and all tokens are either digits or negative integers        if not len(mask) or len(mask) > 2 or not all(                i.isdigit() or int(i) < 0 for r in mask for i in r.strip().split()):            return None        # Convert the lines into a nested list of integers        mask = [list(map(int, row.strip().split())) for row in mask]        # In rows that contain multiple values, ensure all values are non-negative.        # A single -1 is allowed to signal "no valid TES" for that row        if any(i < 0 for r in mask for i in r if len(r) != 1):            return None        # If all checks pass, return the parsed mask data        return mask    def select_mask(self, temperature: int) -> list[list[int]] | None:        """        Selects a valid TES mask file (closest in date, then in temperature) for a dataset.        The method proceeds as follows:          1. If the 'self.mask' attribute is a file path and the file is valid, it returns that mask.          2. Otherwise, it searches within a directory of potential masks, sorting them by date             (relative to the dataset) and then by temperature (closest to the provided 'temperature').          3. Once a valid mask is found, it sets 'self.mask' to that mask and returns it.        :param temperature: The temperature (in mK) of the current dataset.        :type: int        :return: The selected TES mask as a nested list of integers, or None if no valid mask is found.        :rtype: list[list[int]] | None        """        # if 'self.mask' is a single file path, attempt to validate and return it        if os.path.isfile(self.mask):            self.mask = self.check_mask(self.mask)            self.logger.info('Mask selected: %s', self.mask)            return self.mask        # if 'self.mask' is a folder, gather all potential mask files within it.        # Use a wildcard if not already present to match all files in the folder.        masks = glob.glob(self.mask + (os.sep + '*' if '*' not in self.mask else ''))        # Sort the retrieved mask files by their date difference from the dataset.        # The comparison uses 'cmp_mask_by_date', which returns a signed difference in seconds.        masks = sorted(masks,                       key=lambda x: self.cmp_mask_by_date(os.path.basename(self.source),                                                           os.path.basename(x).replace('mask_', '')))        # Regex pattern to extract the temperature in mK from the mask filename        temp_pattern = re.compile(r'(\d+)mK', flags=re.IGNORECASE)        # Extract the dataset date/time from the 'self.source' filename        dtime_ref = dt.strptime('_'.join(os.path.basename(self.source).split('_')[:2]), '%Y-%m-%d_%H.%M.%S')        # Start with the year of the dataset, and then refine the filter by month and day        mask_pattern = str(dtime_ref.year)        # Filter mask files by matching them with the dataset's year, month, and day.        # Each iteration refines the pattern, ensuring we only retain time-compatible masks.        # f'{x:02}': this notation indicates that if the number occupies less than two characters,        # the remaining character is set equal to zero        for token in list(map(lambda x: f'{x:02}', [dtime_ref.month, dtime_ref.day])):            # Filter the list for masks that contain 'mask_pattern'            if not (result := list(filter(lambda x: mask_pattern in x, masks))):                # If no masks match in the current iteration, retain those from the previous step                break            # Restrict 'masks' to those that passed the filter            masks = result            # Extend 'mask_pattern' with the month (and later the day) for a more precise match            mask_pattern = '-'.join([mask_pattern, token])        # At this stage, 'masks' should contain only time-compatible options.        # Now sort them by temperature proximity to the dataset's temperature and pick the first valid one        for mask in sorted(masks, key=lambda x: abs(temperature - int(temp_pattern.search(x).group(1)))):            # Use 'check_mask' to verify the validity of the selected mask file.            if selected_mask := self.check_mask(mask):                self.logger.info('Dataset temp: %s mK | Mask selected: %s', temperature, mask)                self.mask = selected_mask                return self.mask    def make_result_dir(self):        """        Creates a results directory for each dataset under analysis and initializes the logger.        The method does the following:        1. Builds a folder name for storing dataset results.        2. Creates the folder if it doesn't already exist.        3. Sets up the logger, ensuring a unique log file is created for each dataset.        """        # Build the folder name using a prefix plus the base name of the source path        folder = "crd_" + os.path.split(self.source)[-1]        # Combine the destination path and the folder name to get the full results directory path        self.observation_dir = os.path.join(self.dest, folder)        # Create the results directory (if it exists, no exception is raised)        os.makedirs(self.observation_dir, exist_ok=True)        # Construct the full path to the log file        self.logfname = os.path.join(self.observation_dir, f"{folder}.log")        # Configure the logging module so that a new log file is created per dataset        # force = True ensures that one logfile is created for each dataset analysed        logging.basicConfig(filename=self.logfname,                            filemode="w",                            encoding='utf8',                            format="%(asctime)s - %(funcName)s - %(message)s",                            datefmt="%d/%m/%Y | %H:%M:%S",                            level=logging.INFO,                            force=True)        # Create a logger for this module        self.logger = logging.getLogger(__name__)    def export_data(self):        """        Selects a valid mask for the current dataset and exports TES signals according to        the sign specified in the mask. Computes the sampling frequency, saves the housekeeping        time array, elevation values, and the time of the electronics.        Steps:          1. If the time and signals files already exist, load them and compute the sampling frequency.          2. Otherwise, read the dataset from the QubicFP, compute and store the time axis,             select the appropriate mask, and export the masked TES signals to an .npz file.        :return: The list of dataset keys (TES indices) if the files exist; otherwise, returns            an empty list after a new export is performed.        :rtype: list[str]        """        # If both the time file and signals file exist, load and reuse them        if os.path.isfile(self.time_fname) and os.path.isfile(self.signals_fname):            # Load the time axis from the existing .npy file            tm = np.load(self.time_fname)            # Compute the sampling frequency (assume uniform sampling, so fs = 1 / delta_t)            self.fs = 1 / np.median(np.diff(tm))            # Return the list of keys (TES indices) from the loaded signals .npz file            return np.load(self.signals_fname).files        # Otherwise, export data from QubicFP        print("Exporting data via qubicfp...", end="")        # Create a QubicFP instance and suppress verbosity for minimal console output        qubic = qubicfp()        qubic.verbosity = 0        # Read QubicStudio dataset from the directory specified by self.source        qubic.read_qubicstudio_dataset(datadir=self.source)        # retrieve all non-null asics        asics = [asic for asic in qubic.asic_list if asic]        # Verify that all ASICs share (approximately) the same bias voltage.        # Retrieves for each ASIC the v_bias values associated with each time instant        vbias_arrays = [asic.timeline_vbias for asic in asics]        self.logger.info("length of timeline_vbias for asic 0: %s", len(vbias_arrays[0]))        # Reduce each array to its median value        vbias_scalars = [np.median(vbias) for vbias in vbias_arrays]        # Check equality within numerical tolerance        if not np.allclose(vbias_scalars, vbias_scalars[0], rtol=1e-4, atol=1e-4):            self.logger.error("ERROR: Vbias differs between ASICs (values: %s)", vbias_scalars)        # Use the first scalar (they should all be equal) as dataset bias        self.logger.info("vbias: %s", vbias_scalars[0])        # Retrieve the time axis (tm) and the corresponding TES signals        tm, signals = qubic.tod()        tm -= tm[0]        # Compute the sampling frequency from the time axis        self.fs = 1 / np.median(np.diff(tm))        # Convert the measured temperature from K to mK and select the appropriate mask        # (qubic.temperature is expressed in K)        self.mask = self.select_mask(temperature=round(qubic.temperature * 1000))        def _axis_is_valid(axis):            """            True if axis exists, it's not empty and has the same shape of elev            """            return axis is not None and len(axis) != 0 and axis.shape == elev.shape        az = qubic.azimuth()        elev = qubic.elevation()        # np.astype is used to resolve mismatch with Endianess        az = az.astype(np.float64) if az is not None else np.zeros(1)        elev = elev.astype(np.float64) if elev is not None else np.zeros(1)        # Attempt to read housekeeping (HK) and platform time data        t_hk = qubic.timeaxis(datatype='hk')        t_plt = qubic.timeaxis(datatype='platform')        if _axis_is_valid(t_hk):            t_sel = t_hk            axis_name = "HK"        elif _axis_is_valid(t_plt):            t_sel = t_plt            axis_name = "platform"        else:            msg = ("Neither HK nor platform time axis is usable: missing/empty or "                   "shape mismatch with elevation. Proceeding without elevation/azimuth interpolation.")            self.logger.warning(msg)            print(msg)            # Fallback: use the electronics time axis itself            t_sel = tm.astype(np.float64)            axis_name = "electronics"            # Create placeholder elevation and azimuth arrays filled with zeros that match the TOD length            elev = np.zeros_like(tm, dtype=np.float64)            az = np.zeros_like(tm, dtype=np.float64)        t_sel = t_sel.astype(np.float64)        t_sel -= t_sel[0]        # Interpolate elevation over the electronics time axis and save it        np.save(self.elev_fname, np.interp(tm, t_sel, elev))        np.save(self.az_fname, np.interp(tm, t_sel, az))        self.logger.info(f"Used `{axis_name}` time axis ({len(t_sel)} samples) to interpolate elevation and azimuth.")        # Save the shifted time array to .npy        np.save(self.time_fname, tm)        # Prepare lists to store TES indices (keys) and their corresponding signals (masked)        keys = []        masked = []        # If no valid mask is specified, consider all TES indices (positive) by default        self.mask = self.mask or [list(range(signals.shape[0]))]        # For each row in the mask:        #   • Row 0 corresponds to positive TES        #   • Row 1 corresponds to negative TES        for row in range(len(self.mask)):            # If this row contains only -1, skip because it indicates no valid TES for that sign            if len(self.mask[row]) == 1 and self.mask[row][0] == -1:                continue            # Iterate over the TES indices in the current row            for tes in self.mask[row]:                # If the TES index is out of range, stop processing                if tes >= len(signals):                    raise IndexError(f"Invalid TES index {tes} (max: {len(signals) - 1}).")                # Record the TES index as a string key (to save signals in the npz file,                # the TES indices must be strings).                keys.append(str(tes))                # Multiply the signal by (-1)^row to account for sign                sig_signed = (-1) ** row * signals[tes]                masked.append(sig_signed)        cleaned = dict(zip(keys, masked))        # if azimuth and elevation exist, preprocess the signal        # some datasets have bad elevation (> 1000)        if not np.all(az == 0.0) and not np.all(elev == 0.0) and not np.any(np.abs(elev) > 70):            # If you only have one TES to process, atleast_2d converts an array into a matrix,            # since signals is always a matrix            dataset = pp.Dataset(tm=tm,                                 signals=np.atleast_2d(masked),                                 tm_hk=t_sel,                                 elevation=elev,                                 azimuth=az,                                 lag_dt=0.191)            self.logger.info("Electronic: %s, Housekeeping: %s", dataset.f_sampling, dataset.f_sampling_hk)            preprocess = pp.PreProcess(data=None, dataset=dataset, output=self.output_dir, logger=self.logger)            cleaned = preprocess.multiprocess_preproc(tes_list=keys, make_plot=True)        # if it is not an alt-azimuth scan, simply remove the median from the signal        else:            self.logger.warning("No elevation or azimuth data available, removing global median from signal.")            cleaned = {k: sig - np.median(sig) for k, sig in cleaned.items()}        # Save the TES signals in an .npz file, using TES indices as keys        np.savez(self.signals_fname, **cleaned)        # In the event that azimuth and elevation do not exist,        # we created placeholders, and therefore the related files can be deleted.        if axis_name == "electronics":            os.remove(self.elev_fname)            os.remove(self.az_fname)        # some datasets have bad elevation (> 1000)        if np.any(np.abs(elev) > 70):            msg = f"Elevation out of range, removing file `{self.elev_fname}`"            self.logger.warning(msg)            print(msg)            os.remove(self.elev_fname)        return list(map(int, keys))    def configure_data(self):        """        Creates all necessary directories for input/output data, sets up the paths        used during analysis, and exports the required data files for processing.        Specifically, this method performs the following steps:          1. Logs details about the input/output folder configuration and dataset source.          2. Builds paths for input, output, and plot directories, then creates them if needed.          3. Defines filenames for time arrays and cleaned signals,             interpolated elevation and azimuth (if available), and cosmic ray time constants (taus).          4. Exports the preprocessed TES data (and any required additional data) for analysis.        """        self.logger.info('input and output folders of preprocessed data (npy, npz files + taus, plots): %s',                         self.dest)        self.logger.info('folder containing observation data in .fits format: %s',                         self.source)        # Build the path for input and output directories within the results folder        self.input_dir = os.path.join(self.observation_dir, "input")        self.output_dir = os.path.join(self.observation_dir, "output")        self.logger.info('input dir: %s', self.input_dir)        self.logger.info('output dir: %s', self.output_dir)        # Create the input and output directories if they do not exist        os.makedirs(self.input_dir, exist_ok=True)        os.makedirs(self.output_dir, exist_ok=True)        self.logger.info('input dir created')        self.logger.info('output dir created')        # Define file paths for the time array, cleaned signals, and interpolated elevation and azimuth data        self.time_fname = os.path.join(self.input_dir, "dt_time.npy")        self.signals_fname = os.path.join(self.input_dir, "signals.npz")        self.elev_fname = os.path.join(self.input_dir, "elevation.npy")        self.az_fname = os.path.join(self.input_dir, "azimuth.npy")        # Define the path for cosmic ray time constants (taus) output        self.taus_fname = os.path.join(self.output_dir,                                       f"crd_taus__{os.path.split(self.observation_dir)[-1]}.json")        self.logger.info('time file path: %s', self.time_fname)        self.logger.info('raw signal file path: %s', self.signals_fname)        self.logger.info('interp elevation file path: %s', self.elev_fname)        self.logger.info('taus file path: %s', self.taus_fname)        # Build and log the plots directory path        self.plots_dir = os.path.join(self.output_dir, "plots")        self.logger.info('plots dir: %s', self.plots_dir)        # Create the plots directory if it does not already exist        os.makedirs(self.plots_dir, exist_ok=True)        self.logger.info('plots dir created')        # Finally, export the data (TES signals, housekeeping info, etc.) for further analysis        return self.export_data()    @staticmethod    @nb.njit(nogil=True, cache=True)    def get_candidates(signal: np.ndarray, std_coeff: float) -> list[list[int]]:        """        Identifies potential cosmic ray candidates in the TES signal.        Each candidate must show a vertical increase (linear growth) followed by        an exponential decrease.        When the signal exceeds the threshold set to s_mean + std_coeff * s_std,        it triggers the search for the characteristic CR pattern.        The algorithm checks whether the data points immediately following the initial trigger point conform        to an exponential decay. This check is applied specifically to the first point        above the threshold because the method is designed to detect prominent signal bumps, whose decaying        nature is immediately identified after the bump.        :param signal: Array containing the TES signal values        :type: np.ndarray        :param std_coeff: coefficient used to compute the threshold for candidate detection.        :type: float        :param lower: A lower-bound threshold (default is mean(signal) + std(signal)).            If the signal goes below this threshold, the candidate search ends.        :type: float, optional        :return: A list of [start_index, end_index] pairs representing each detected cosmic ray candidate.        :rtype: list[list[int]]        """        # Compute the standard deviation of the signal        s_std = signal.std()        # Compute the mean of the signal        s_mean = signal.mean()        # Define lower and upper thresholds for candidate search:        lower = s_std + s_mean        upper = s_mean + std_coeff * s_std        # Define mask for candidate search        mask = signal > upper        candidates = []        if mask.any():            # indices upper threshold            idx_up_threshold = np.where(mask)[0]            # groups ending indices            group_idx = np.where(np.diff(idx_up_threshold) > 1)[0]            groups = np.split(idx_up_threshold, group_idx + 1)            for i, group in enumerate(groups):                check = False                idx = group[0]                while signal[idx] > signal[min(idx + 1, len(signal) - 1)]:                    idx += 1                    check = True                # find the number of growth points.                # this while loop stops one index BEFORE the last value                # that satisfies the condition, so when I save the candidate                # I have to subtract 1 from start                while check and signal[max(group[0] - 1, 0)] > signal[max(group[0] - 2, 0)] > lower:                    group[0] -= 1                # self.logger.info('The %s group strats at index %s and has %s decreasing points', i, group[0], idx - group[0] + 1)                if check:                    candidates.append([max(int(group[0]) - 1, 0), int(idx + 1)])        return candidates    def check_mode(self, tes_keys: list[int]) -> list[int]:        """        Checks and sets the TES analysis mode. The possible modes are:          • 'all': Analyze all TES.          • 'range': Analyze a continuous range of TES indices (e.g., [10, 20]).          • 'sequence': Analyze a sequence of TES indices (e.g., [1, 5, 80, 100]).        :param tes_keys: The keys corresponding to the TES signals present in the .npz files.        :type: list[int]        :return: A list of TES indices to be analyzed according to the chosen mode.        :rtype: list[int]        """        # If the analysis mode indicates 'all' (i.e., a single value -1), analyze all available TES        if len(self.analysis_type_args) == 1 and self.analysis_type_args[0] == -1:            self.analysis_type_args = tes_keys        # Otherwise, if no arguments exist or there is an invalid TES in the list, raise an error        elif not self.analysis_type_args or (                isinstance(self.analysis_type_args, list) and any(            tes not in tes_keys for tes in self.analysis_type_args)):            error = (f"Some selected TES are invalid\n{self.analysis_type =} | {self.analysis_type_args=}\n"                     f"Available tes index: {tes_keys}")            raise ValueError(error)        # If the mode is 'range', reduce self.analysis_type_args to the specified interval        if self.analysis_type == 'range':            self.analysis_type_args = tes_keys[tes_keys.index(self.analysis_type_args[0]): tes_keys.index(                self.analysis_type_args[1]) + 1]        # If the mode is 'sequence', use self.analysis_type_args as-is (already a sequence)        elif self.analysis_type == 'sequence':            # No changes needed; self.analysis_type_args is already the sequence of TES            pass        # If the mode is neither 'range' nor 'sequence', default to analyzing all valid TES        else:            self.analysis_type_args = tes_keys        # Log the mode and the final list of TES to be analyzed        self.logger.info("Mode: %s | Tes: %s", self.analysis_type, self.analysis_type_args)        return self.analysis_type_args    def get_taus(self, tes_idx: list[int]) -> dict[int, dict[str, list[float]]]:        """        Computes and returns the time constants (taus) for each TES (Transition Edge Sensor)        by processing their cleaned signals and fitting an exponential decay model.        :param tes_idx: List of all available TES indices for analysis.        :type: list[int]        :return: A dictionary where each key is a TES index and its value is another dictionary            containing details about the time constant (tau) and associated fit parameters.            The inner dictionary includes keys such as:              - 'taus': list of time constants (tau)              - 'tes': the TES and asic identifiers              - 'exp fit params': exponential fit parameters              - 'sigma': standard deviation from the fit              - 'chi square': chi-square statistics of the fit              - 'residuals': residuals from the fit              - 'indexes': indexes corresponding to the candidate region in the signal        :rtype: dict[int, dict[str, list[float]]]        """        # Counter to track the total number of time constants found        all_taus_found = 0        # Determine which TES to analyze based on the user-selected mode        iter_ = self.check_mode(tes_idx)        # Load the raw time array and the preprocessed signals from file        time_raw = np.load(self.time_fname)        signals = np.load(self.signals_fname)        # Create a multiprocessing pool to parallelize candidate processing and fitting        with mp.Pool() as pool:            # Iterate over each TES index to process its signal, with a progress bar            for n_tes in tqdm(iter_, ncols=100, file=sys.stdout, desc="Progress", unit='tes', leave=False):                # Retrieve the signal for the current TES (using a string key)                signal = signals[str(n_tes)]                # I retrieve the data for each candidate starting from the entire signal and time arrays                candidates = Crd.get_candidates(signal=signal, std_coeff=self.std_coeff)                self.logger.info('Number of candidates found: %s', len(candidates))                # If candidates are found, further process them                if candidates:                    # Determine chunk size for multiprocessing based on the number of candidates and CPU cores                    chunksize = max(1, len(candidates) // mp.cpu_count())                    tm_candidates = []                    sig_candidates = []                    noise_before = []                    noise_after = []                    for start, stop in candidates:                        tm_candidates.append(time_raw[start:stop])                        sig_candidates.append(signal[start:stop])                        if start - self.noise_points > 0:                            noise_before.append(signal[start - self.noise_points:start])                        else:                            noise_before.append(None)                        if stop + self.noise_points < len(signal):                            noise_after.append(signal[stop:stop + self.noise_points])                        else:                            noise_before.append(None)                    # Apply a multiprocessing filter to refine candidates using the candidate_filter function                    candidates = md.multiprocess_filter(pool=pool,                                                        candidates=candidates,                                                        function=md.candidate_filter,                                                        args=zip(tm_candidates,                                                                 sig_candidates,                                                                 noise_before,                                                                 noise_after,                                                                 [self.points_vertical_trend] * len(candidates)),                                                        chunksize=chunksize)                    # Recalculate chunksize for the filtered candidate list                    chunksize = max(1, len(candidates) // mp.cpu_count())                    # Update time and signal segments for the valid candidates                    tm_candidates = map(lambda c: time_raw[c[0]: c[1]], candidates)                    sig_candidates = map(lambda c: signal[c[0]: c[1]], candidates)                    # Define an offset to capture additional points around candidates                    # for standard deviation calculation                    std_offset = 20                    # Compute the standard deviation for each candidate by considering extra points before and after                    std_candidates = map(lambda c:                                         np.array([*signal[max(0, c[0] - std_offset): c[0]],                                                   *signal[c[1]: min(len(signal), c[1] + std_offset)]]).std(),                                         candidates)                    # Apply a fitting function to each candidate to obtain a matrix of fit parameters                    # (n candidates x 6) -> (a,b,c, std(tau), degrees of freedom, reduced chi square, pvalue)                    taus_matrix = pool.starmap(md.get_fit_candidate,                                               zip(tm_candidates, sig_candidates, std_candidates),                                               chunksize)                    # Map the fit results to time constants                    valid_results = [(fr, idxs) for fr, idxs in zip(taus_matrix, candidates) if fr]                    if valid_results:                        all_taus_found += len(valid_results)                        tes, asic = get_tes_asic_from_index(int(n_tes))                        # Collect all fields using zip and unpacking                        taus, params, pcov, sigma, chi_sq, res, slopes, slope_errs, slope_p_values, idxs = zip(                            *[                                (                                    fr.tau,                                    [fr.a, fr.b, fr.c],                                    fr.pcov,                                    fr.sigma_tau,                                    [fr.nu, fr.chi_square_reduced, fr.p_value],                                    fr.residuals,                                    fr.slope,                                    fr.slope_sigma,                                    fr.slope_p_value,                                    idx                                )                                for fr, idx in valid_results                            ]                        )                        self.taus[n_tes] = {                            'taus': taus,                            'tes': [tes, asic],                            'exp fit params': params,                            'covariance matrix': pcov,                            'sigma': sigma,                            'chi square': chi_sq,                            'residuals': res,                            'slopes': slopes,                            'slope errs': slope_errs,                            'slope p values': slope_p_values,                            'indexes': idxs                        }                        self.logger.info("#Tes (index): %s | #Time constants: %s", n_tes, len(taus))        # Log the total number of time constants found across all TESs        self.logger.info("Number of time constants for all TESs: %s", all_taus_found)        # Return the dictionary containing time constants and fit parameters for each TES        return self.taus    def multidataset_report(self,                            fname: str,                            mdt_report: dict,                            make_plot: bool = False,                            global_dest: str = None,                            title: str = None):        """        Provides general insights based on the analysis results from individual datasets.        It visualizes cosmic ray occurrences as a function of amplitude, event duration,        and instrument elevation. For each TES, it also displays the estimated time constant        along with its associated uncertainty.        :param fname: base filename or data path used for saving outputs.        :type: str        :param mdt_report: Dictionary containing all necessary information to generate the plots.        :type: dict        :param make_plot: If True, generate plots of the analysis results (default is False).        :type: bool, optional        :param global_dest: Destination folder for saving the analysis outputs; if not provided, self.dest is used.        :type: str, optional        :param title: Title to be used for the generated plot (if any).        :type: str, optional        """        # Initialize an empty list for elevation values        elev = []        if not os.path.exists(self.signals_fname):            return        # Load the preprocessed TES signals from file        signals = np.load(self.signals_fname)        # Load the time array corresponding to the signals        tm_signals = np.load(self.time_fname)        # Check if an interpolated elevation file exists        if os.path.isfile(self.elev_fname):            # Load elevation data if available            elev = np.load(self.elev_fname)        # Loop over each TES for which time constants have been computed        for tes in self.taus:            # Retrieve the signal for the current TES using its string key            sig = signals[str(tes)]            # If the TES is not yet in the multidataset report, initialize its structure            if tes not in mdt_report:                mdt_report[tes] = dict()  # Create a new dictionary for this TES                mdt_report[tes]['taus'] = list()  # Initialize a list for time constants                mdt_report[tes]['energy'] = list()  # Initialize a list for cosmic ray event amplitudes                mdt_report[tes]['elevation'] = list()  # Initialize a list for elevations at event occurrences                mdt_report[tes]['time'] = list()  # Initialize a list for event durations                mdt_report[tes]['residuals'] = list()  # Initialize a list for fit residuals                # counters used to compute nu_tau = N_tau / T_obs across many datasets                mdt_report[tes]['taus_count'] = 0  # cumulative number of τ for this TES                mdt_report[tes]['obs_time'] = 0.0  # cumulative observation time [s] for this TES            energy = []  # List to store energy (amplitude) for current TES            taus_tm = []  # List to store event duration (time differences) for current TES            tes_taus = []  # List to store time constant and its uncertainty for current TES            elevation = []  # List to store elevation data corresponding to events            residuals = []  # List to collect residuals from candidate fits            # Total observation time for this dataset (seconds)            obs_time_ds = (tm_signals[1] * len(tm_signals)) if len(tm_signals) > 1 else 0.0            # Calculates the order of magnitude of the time constants found for a given TES.            # Issues a warning if a TES has all the taus of a different order of magnitude.            # exp = np.round(np.log10(self.taus[tes]['taus']))            # if not (np.ptp(exp) == 0):            #     self.logger.warning("TES %d does not have same order time constants", tes)            #     continue            # Iterate over computed taus for current TES            for idx, tau in enumerate(self.taus[tes]['taus']):                # Retrieve start and stop indices for the candidate                start, stop = self.taus[tes]['indexes'][idx]                # Calculate and store the duration of the candidate event                taus_tm.append(tm_signals[stop - 1] - tm_signals[start])                # Append the time constant along with its uncertainty for this candidate                tes_taus.append([tau, self.taus[tes]['sigma'][idx]])                # Calculate event energy as the difference between max and min signal values in the candidate range                energy.append(sig[start:stop].max() - sig[start:stop].min())                # Extend the residuals list with residuals from the candidate fit                residuals.extend(self.taus[tes]['residuals'][idx])                # If elevation data is available, calculate and append the mean elevation for the candidate event                if len(elev):                    elevation.append(                        elev[start:stop].mean() if elev[0] > elev[-1] else (90 - elev[start:stop]).mean())            if tes_taus:                # Update the multidataset report for the current TES with the collected data                mdt_report[tes]['taus'].extend(tes_taus)                mdt_report[tes]['energy'].extend(energy)                mdt_report[tes]['elevation'].extend(elevation)                mdt_report[tes]['time'].extend(taus_tm)                mdt_report[tes]['residuals'].extend(residuals)                # accumulate the number of taus and observation time for frequency calculation                mdt_report[tes]['taus_count'] += len(tes_taus)                mdt_report[tes]['obs_time'] += obs_time_ds            else:                del mdt_report[tes]        # If plotting is requested, generate the multidataset report plots.        # When the code analyzes the last dataset of a given scanning strategy        # or the last dataset among all those to be analyzed (regardless of the scanning strategy),        # the multi dataset plot is generated        if make_plot and mdt_report.keys():            energy = []  # Reinitialize the energy list for aggregated plotting.            taus_tm = []  # Reinitialize the total event duration (rising and decreasing part) list for plotting.            average_taus_per_tes = []  # List to collect averaged tau values from each TES.            elevation = []  # List to collect elevation data for all TES.            residuals = []  # List to collect all residuals for plotting.            tes_with_taus = []  # List to record TES indices that have estimated taus.            all_taus_sigma = []  # list to collect taus and their sigmas from all datasets, from all TES            fig_kw = dict(figsize=(12, 6), tight_layout=True)  # Figure keyword arguments for plot styling            # Loop over each TES in the multidataset report            for tes in mdt_report:                # If the TES has computed time constants, calculate its average tau and uncertainty                if mdt_report[tes]['taus']:                    all_taus_sigma.extend(mdt_report[tes]['taus'])                    mean_tau, mean_sigma = np.mean(mdt_report[tes]['taus'], axis=0)                    mdt_report[tes]['tau'] = [mean_tau, mean_sigma / len(mdt_report[tes]['taus']) ** 0.5]                    tes_with_taus.append(tes)  # Add TES index to the list                    average_taus_per_tes.append(mdt_report[tes]['tau'])  # Append the averaged tau and sigma                    energy.extend(mdt_report[tes]['energy'])  # Aggregate energy values                    elevation.extend(mdt_report[tes]['elevation'])  # Aggregate elevation data                    taus_tm.extend(mdt_report[tes]['time'])  # Aggregate event duration values                    residuals.extend(mdt_report[tes]['residuals'])  # Aggregate fit residuals                    # store nu_tau = N_tau / T_obs for this TES                    mdt_report[tes]['nu_tau'] = (                        mdt_report[tes]['taus_count'] / mdt_report[tes]['obs_time']                        if mdt_report[tes]['obs_time'] else np.nan                    )            # at this point all_taus_sigma contains the time constants and related uncertainties found for            # each TES and for each dataset analyzed.            # Now I want to calculate the global average tau and the global average uncertainty            # (all TES and all datasets).            # ex: Let's assume that only one TES and for a single dataset found a tau,            # operation np.mean([tau=1, std=2], axis=0) would return 1.5 , but I would like [1. , 2.]            # so I need np.atleast_2d to consider all_taus_sigma at least 2d, so the mean will return [1., 2.]            all_taus_sigma = np.atleast_2d(all_taus_sigma)            # Frequencies of taus per TES (same order as tes_with_taus)            nu_tau_per_tes = [mdt_report[tes]['nu_tau'] for tes in tes_with_taus]            if all_taus_sigma.size:                # Use the unweighted arithmetic mean and its standard error                taus = all_taus_sigma[:, 0]                global_average_tau = np.mean(taus)                # sample standard deviation (ddof=1)                global_average_sigma = np.std(taus, ddof=1)            else:                global_average_tau, global_average_sigma = np.nan, np.nan            # Create a figure and axes via subplot_mosaic: 3 on the top row (A,B,C), 2 on the bottom (D,E)            layout = "ABC\nDEE"            hist_fig, axes = plt.subplot_mosaic(layout, **fig_kw)            ax_amp, ax_elev, ax_tm, ax_res, ax_tau = axes.values()            # Set the overall title of the figure, with spaces replaced by non-breaking spaces for formatting            title = title.replace(' ', r' \; ')            hist_fig.suptitle(rf"${title}$")            # Plot histogram of cosmic ray amplitudes with a Landau distribution fit            my_plt.plot_hist(ax_amp,                             r'$\tau ~ vs ~ Amplitudes$',                             r'$ Amplitude \ [ADU]$',                             None,                             '',                             '',                             to_plot=energy,                             fit_func=landau,                             fit_name_args=("loc = {:.4f},", "scale = {:.4f}"))            # Plot histogram of elevation values            my_plt.plot_hist(ax_elev,                             r'$ \tau ~ vs ~ Elevation$',                             r'$ Elevation ~ [degrees]$',                             None,                             '',                             '',                             to_plot=elevation)            # Scatter plot of nu_tau per TES across all datasets            ax_tm.scatter(tes_with_taus, nu_tau_per_tes, color='black', marker='o', s=8)            ax_tm.set(facecolor='whitesmoke',                      title=r'$\nu_{\tau} \ per \ TES$',                      xlabel=r'$\# TES$',                      ylabel=r'$\nu_{\tau} \ [Hz]$')            ax_tm.grid(True)            # Plot histogram of fit residuals with a normal distribution fit            normCauchy = MixedDistribution(norm, cauchy)            my_plt.plot_hist(ax_res,                             title=r'$Cosmic ~ Rays ~ Residual ~ Fit$',                             xlabel=r'$Residuals$',                             taus=None,                             data_path='',                             to_plot=residuals,                             fit_func=normCauchy,                             fit_name_args=(r'{:.2f} \% ~ outliers',),                             datatype="residuals")            # Configure the subplot for displaying estimated time constants for each TES            ax_tau.set(facecolor='whitesmoke',                       title=r"$Estimation~of~\tau: ~ {global_average_tau:.3g} \pm {global_average_sigma:.3f}$ [s]",                       xlabel=r'$ \# TES$',                       ylabel=r'$\tau$')            # Plot error bars for the time constants with their uncertainties            ax_tau.errorbar(tes_with_taus, [t[0] for t in average_taus_per_tes], [t[1] for t in average_taus_per_tes],                            fmt='o', color='steelblue')            ax_tau.grid(True)            # Compute percentiles for the estimated tau values            tau_values = [t[0] for t in average_taus_per_tes]            percentiles = np.percentile(tau_values, [25, 50, 75])            labels = [rf'${p}\%~=~{val:.5f}$' for p, val in zip([25, 50, 75], percentiles)]            for val, label, color in zip(percentiles, labels, ['silver', 'gray', 'black']):                ax_tau.axhline(val, label=label, linestyle='--', color=color)            # Add a legend indicating the coverage percentage (based on number of taus and total TES pixels)            ax_tau.legend(title=rf'$Coverage: ~ {len(average_taus_per_tes) / (2 * NPIXELS) * 100: .2f} \% $')            # Determine the destination folder to save analysis results            dest = global_dest or self.dest            # Save the residuals to a npy file            np.save(os.path.join(dest, f"{fname}_residuals"), residuals)            self.logger.info(f"Saving %s residuals: # samples %s", fname, len(residuals))            # Define the file path for saving the multidataset report figure            mdreport_filepath = os.path.join(dest, fname)            self.logger.info("Saving multidataset report to %s", mdreport_filepath)            hist_fig.savefig(mdreport_filepath, dpi=my_plt.dpi)            # Close the figure to free up resources            plt.close(hist_fig)            # Define the file path for saving the estimated taus as a CSV file            est_taus_filepath = os.path.join(dest, f'{fname}_estimated_tau.csv')            self.logger.info("Saving estimated taus to %s", est_taus_filepath)            # Write the estimated taus to CSV using the write_results utility function            write_results(est_taus_filepath, dict(zip(tes_with_taus, average_taus_per_tes)), fmt="csv",                          header=["ASIC", "TES", "average tau", "sigma"])    def plot_results(self):        """        Generates and saves all analysis plots.        This method performs two main tasks:          1. It creates individual plots for each TES by splitting the available tau data into groups             of three, then parallelizes the plotting process.          2. It produces a summary plot for the entire dataset.        """        # List to hold the global TES indices, repeated according to the number of plots needed        # (each plot shows up to 3 taus)        tes_global_idx = []        # List to hold the tau information dictionary for each TES, repeated as needed for plotting        taus_per_tes_list = []        # List to hold the starting index for plotting taus (each plot displays 3 taus, so indices are 0, 3, 6, etc.)        start_tau_idx = []        # List to hold copies of the paths list for each plotting subprocess        paths_list = []        # Create a multiprocessing pool to parallelize the creation of individual TES plots        with mp.Pool() as pool:            # Define a list of paths used in plotting:            # Observation directory, plots directory, cleaned signals, interpolated elevation, and time file            paths = (                self.observation_dir,                self.plots_dir,                self.signals_fname,                self.elev_fname,                self.time_fname            )            # Loop over each TES for which tau data is available            for tes in self.taus:                tes_taus = len(self.taus[tes]['taus'])  # Number of tau entries for the current TES                n_plots = round(tes_taus / 3)  # Estimate the number of plots needed (each plot shows 3 taus)                # Calculate the total iterations: n_plots plus an extra plot if there are remaining taus                n_iter = n_plots + (tes_taus - 3 * n_plots) * (3 * n_plots < tes_taus)                # Extend the list of global TES indices with the current TES, repeated n_iter times                tes_global_idx.extend([int(tes)] * n_iter)                # Extend the list with the tau data for the current TES, repeated n_iter times                taus_per_tes_list.extend([self.taus[tes]] * n_iter)                # Extend the list with copies of the paths list for each plot to be generated                paths_list.extend([paths] * n_iter)                # Extend the list with starting indices for each plot (0, 3, 6, etc.)                start_tau_idx.extend([3 * i for i in range(n_iter)])            # Parallelize the creation of individual TES plots using the starmap function            pool.starmap(my_plt.plot_taus,                         zip(tes_global_idx,                             taus_per_tes_list,                             paths_list,                             start_tau_idx),                         chunksize=max(1, len(tes_global_idx) // mp.cpu_count()))        # After parallel plotting, generate a summary plot for the entire dataset        my_plt.plot_taus(0, self.taus, paths, 0, 10, self.thermometers, summary_plot=True)    def _find_cosmic_rays(self) -> (dict, int):        """        Searches for cosmic ray events based on computed time constants from TES signals.        This method configures the necessary data directories, exports cleaned signals,        computes time constants for each TES, saves the residuals, writes the results to a file,        and generates the required plots for the analysis.        :return: A tuple where the first element is a dictionary with cosmic ray information            for each TES and the second element is the total number of cosmic ray events found.        :rtype: (dict, int)        """        # Log initial configuration info        self.logger.info("configuration of all the necessary variables")        # Configure directories and paths for exported files (.npy and .npz formats)        tes_keys = self.configure_data()        # skip the dataset if no valid TES data are available (bad iv curve)        if not tes_keys:            return {}, 0        # Log the start of time constant extraction        self.logger.info("search for the time constants of all TESs")        # Start a timer to measure processing time        start = tm.perf_counter()        # Compute time constants for the available TES        taus_per_tes = self.get_taus(tes_keys)        # Initialize a list to gather residuals from candidate fits        residuals = []        res: list[float]        for tes in taus_per_tes:            # Flatten residuals from each TES into a single list            residuals.extend([value for res in taus_per_tes[tes]['residuals'] for value in res])        if residuals:            # Save residuals to a file if any residuals were collected            np.save(os.path.join(self.output_dir, "residuals"), residuals)            self.logger.info(f"Saving single dataset residuals: # samples {len(residuals)}")        end = tm.perf_counter()        execution_time = f"Time to process signals: {end - start:.2f}[s]"        # Log the execution time        self.logger.info(execution_time)        print("\033[96m" + execution_time + "...\033[00m", end="")        self.logger.info("write time constants to the file '%s'", self.taus_fname)        # Write the computed time constants to a file        write_results(self.taus_fname, taus_per_tes)        taus_per_dataset = len([tau for tes in taus_per_tes for tau in taus_per_tes[tes]['taus']])        self.logger.info("save the time constant plots for single TES and the time constant plot of all TES")        print("\033[0;33m" + f"Found {taus_per_dataset} taus. " + "\033[00m", end="")        # Generate and save the individual and summary plots for the time constants        self.plot_results()        end = "Analysis completed successfully"        print("\033[32m" + end + "\033[00m", end='\n\n')        self.logger.info(end)        # Return the dictionary of cosmic ray events per TES and the total number of cosmic ray events found        return taus_per_tes, taus_per_dataset    def find_cosmic_rays(self):        """        Manages the process of cosmic ray detection by coordinating various methods.        It verifies the analysis mode and available datasets, processes each dataset for cosmic ray detection,        generates multi-dataset reports if applicable, and optionally removes temporary files.        """        # Check if the analysis type is valid, according to the allowed modes in Crd.MODE        if self.analysis_type not in Crd.MODE:            raise ValueError(f"mode must be one of {Crd.MODE}")        # Retrieve the datasets to be analyzed; if none are found, raise an error        if not (datasets := self.get_datasets()):            raise ValueError("no datasets found")        # If there are at least two datasets and file removal is not enabled,        # warn the user about large disk space usage and prompt whether to remove files        if sum(map(len, datasets.values())) >= 2 and not self.remove_files:            warning = """\033[91mWarning!                    You have selected more than two datasets to analyze, and you haven't requested                     the removal of .npy and .npz files. Keep in mind that analyzing a single dataset generates .npy and .npz files                     that will take up approximately 9 GB of space in total! Do you want to MAINTAIN all the .npy and .npz files                     that will be created (NOT recommended action)? [y/n]\033[0m """            self.remove_files = input(warning).lower() != 'y'        # Initialize a list to store Crd objects for datasets with detected cosmic rays        crds = list()        # Initialize a dictionary to collect the results        results = dict()        # Get the path of the last dataset (used later for global multi-dataset report plotting)        last_path = list(datasets.values())[-1][-1]        # Iterate over each scanning strategy in the datasets        for strategy in datasets:            if not datasets[strategy]:                msg = "No datasets found for scanning strategy '{}'"                print(f"[WARNING] + " + msg.format(strategy))                self.logger.warning(msg, strategy)                continue            # List to collect datasets for which no cosmic rays were found            no_crd = list()            # Create an entry in the results dictionary for this strategy            results[os.path.basename(strategy)] = dict()            # Identify the last dataset path for the current scanning strategy            scan_strat_last_path = datasets[strategy][-1]            # If more than one dataset exists for this strategy, initialize a Crd object for multi-dataset reporting            if len(datasets[strategy]) > 1:                scan_strat_crd = Crd(source=f'scan_strat_{os.path.basename(strategy)}',                                     dest=strategy,                                     points_vertical_trend=self.points_vertical_trend,                                     points_exp_decrease=self.points_exp_decrease)            # Process each dataset (source) within the current scanning strategy            for src in datasets[strategy]:                # Create a Crd object for the current dataset with the specified analysis parameters                crd = Crd(source=src,                          dest=strategy,                          points_vertical_trend=self.points_vertical_trend,                          points_exp_decrease=self.points_exp_decrease,                          mask=self.mask,                          analysis_type=self.analysis_type,                          analysis_type_args=self.analysis_type_args,                          remove_files=self.remove_files,                          save_results=self.save_results)                # Create all necessary directories to store analysis results                crd.make_result_dir()                crd.logger.info('observation dir: %s', crd.observation_dir)                print('\033[45m' + f'Dataset under analysis: {src}' + '\033[00m')                try:                    # Execute cosmic ray detection on the dataset and retrieve tau results and count                    taus, n_taus = crd._find_cosmic_rays()                    # If multiple datasets exist for the scanning strategy, generate a multi-dataset report for this                    # strategy                    if len(datasets[strategy]) > 1:                        crd.multidataset_report(fname=os.path.basename(strategy),                                                mdt_report=scan_strat_crd.taus,                                                make_plot=src == scan_strat_last_path,                                                title=f'Multi-Dataset Analysis - Scanning Strategy: '                                                      f'{os.path.basename(strategy)}')                    # If more than one scanning strategy is being analyzed, generate a global multi-dataset report                    if len(datasets) > 1:                        # the plot is created only when the provided dataset is the final one to be analyzed                        crd.multidataset_report(fname='all_datasets',                                                mdt_report=self.taus,                                                make_plot=src == last_path,                                                global_dest=self.dest,                                                title="Multi-Dataset Analysis - All Scanning Strategies")                    # If file removal is enabled, delete temporary .npy and .npz files (except for the necessary                    # cleaned signals file)                    if self.remove_files:                        # Keep only the main signals .npz, remove everything else in input_dir                        keep_file = os.path.basename(crd.signals_fname)                        for file in glob.glob(os.path.join(crd.input_dir, '*')):                            if os.path.basename(file) != keep_file:                                os.remove(file)                        # If the plots directory is empty after removals, remove it along with the tau file and                        # output directory                        if not os.listdir(crd.plots_dir):                            os.rmdir(crd.plots_dir)                            shutil.rmtree(crd.output_dir)                            crd.logger.info('No time constants found. Plots dir removed')                    # If tau candidates are found, store the count in the results and add the Crd object to the list;                    # otherwise, mark the dataset as free of cosmic rays                    if n_taus:                        results[os.path.basename(strategy)][os.path.basename(src)] = n_taus                        crds.append(crd)                    else:                        no_crd.append([crd.logfname, crd.observation_dir])                except Exception as e:                    print(f"\033[31mERROR: {e} \033[0m")                    crd.logger.exception("Exception while executing find_cosmic_rays")            # Shutdown logging for the current strategy to close all log files            logging.shutdown()            # For datasets with no detected cosmic rays, move log files and remove associated directories            # if file removal is enabled            for dataset in no_crd:                if self.remove_files:                    try:                        shutil.move(dataset[0], strategy)                        shutil.rmtree(dataset[1])                    except Exception as e:                        print(f"\033[31mERROR: {e} \033[0m")        # If saving results is enabled, write the cosmic ray detection results to a JSON file        if self.save_results:            write_results(os.path.join(self.dest, 'cosmic_rays_detected.json'), results, indent=2)        print('\033[42m' + 'ALL DATASET ANALYZED' + '\033[00m')        return crdsif __name__ == '__main__':    mp.set_start_method("spawn")    # Check if the configuration file (passed as the first command-line argument) exists    if not os.path.isfile(conf := sys.argv[1]):        # Raise an error if the file is not found        raise ValueError(f'File `{conf}` not found')    # Create a Crd object by reading the configuration from the specified file    crd = Crd.read_config(conf)    # Run the cosmic ray detection analysis    crd.find_cosmic_rays()